1409 /// Add a VPEVLBasedIVPHIRecipe and related recipes to \p Plan and
1410 /// replaces all uses except the canonical IV increment of
1411 /// VPCanonicalIVPHIRecipe with a VPEVLBasedIVPHIRecipe. VPCanonicalIVPHIRecipe
1412 /// is used only for loop iterations counting after this transformation.
1413 ///
1414 /// The function uses the following definitions:
1415 ///  %StartV is the canonical induction start value.
1416 ///
1417 /// The function adds the following recipes:
1418 ///
1419 /// vector.ph:
1420 /// ...
1421 ///
1422 /// vector.body:
1423 /// ...
1424 /// %EVLPhi = EXPLICIT-VECTOR-LENGTH-BASED-IV-PHI [ %StartV, %vector.ph ],
1425 ///                                               [ %NextEVLIV, %vector.body ]
1426 /// %AVL = sub original TC, %EVLPhi
1427 /// %VPEVL = EXPLICIT-VECTOR-LENGTH %AVL
1428 /// ...
1429 /// %NextEVLIV = add IVSize (cast i32 %VPEVVL to IVSize), %EVLPhi
1430 /// ...
1431 ///
1432 bool VPlanTransforms::tryAddExplicitVectorLength(VPlan &Plan) {
1433   VPBasicBlock *Header = Plan.getVectorLoopRegion()->getEntryBasicBlock();
1434   // The transform updates all users of inductions to work based on EVL, instead
1435   // of the VF directly. At the moment, widened inductions cannot be updated, so
1436   // bail out if the plan contains any.
1437   bool ContainsWidenInductions = any_of(Header->phis(), [](VPRecipeBase &Phi) {
1438     return isa<VPWidenIntOrFpInductionRecipe, VPWidenPointerInductionRecipe>(
1439         &Phi);
1440   });
1441   // FIXME: Remove this once we can transform (select header_mask, true_value,
1442   // false_value) into vp.merge.
1443   bool ContainsOutloopReductions =
1444       any_of(Header->phis(), [&](VPRecipeBase &Phi) {
1445         auto *R = dyn_cast<VPReductionPHIRecipe>(&Phi);
1446         return R && !R->isInLoop();
1447       });
1448   if (ContainsWidenInductions || ContainsOutloopReductions)
1449     return false;
1450 
1451   auto *CanonicalIVPHI = Plan.getCanonicalIV();
1452   VPValue *StartV = CanonicalIVPHI->getStartValue();
1453 
1454   // Create the ExplicitVectorLengthPhi recipe in the main loop.
1455   auto *EVLPhi = new VPEVLBasedIVPHIRecipe(StartV, DebugLoc());
1456   EVLPhi->insertAfter(CanonicalIVPHI);
1457   // TODO: Add support for MaxSafeDist for correct loop emission.
1458   // Compute original TC - IV as the AVL (application vector length).
1459   auto *AVL = new VPInstruction(Instruction::Sub, {Plan.getTripCount(), EVLPhi},
1460                                 DebugLoc(), "avl");
1461   AVL->insertBefore(*Header, Header->getFirstNonPhi());
1462   auto *VPEVL =
1463       new VPInstruction(VPInstruction::ExplicitVectorLength, AVL, DebugLoc());
1464   VPEVL->insertAfter(AVL);
1465 
1466   auto *CanonicalIVIncrement =
1467       cast<VPInstruction>(CanonicalIVPHI->getBackedgeValue());
1468   VPSingleDefRecipe *OpVPEVL = VPEVL;
1469   if (unsigned IVSize = CanonicalIVPHI->getScalarType()->getScalarSizeInBits();
1470       IVSize != 32) {
1471     OpVPEVL = new VPScalarCastRecipe(IVSize < 32 ? Instruction::Trunc
1472                                                  : Instruction::ZExt,
1473                                      OpVPEVL, CanonicalIVPHI->getScalarType());
1474     OpVPEVL->insertBefore(CanonicalIVIncrement);
1475   }
1476   auto *NextEVLIV =
1477       new VPInstruction(Instruction::Add, {OpVPEVL, EVLPhi},
1478                         {CanonicalIVIncrement->hasNoUnsignedWrap(),
1479                          CanonicalIVIncrement->hasNoSignedWrap()},
1480                         CanonicalIVIncrement->getDebugLoc(), "index.evl.next");
1481   NextEVLIV->insertBefore(CanonicalIVIncrement);
1482   EVLPhi->addOperand(NextEVLIV);
1483 
1484   transformRecipestoEVLRecipes(Plan, *VPEVL);
1485 
1486   // Replace all uses of VPCanonicalIVPHIRecipe by
1487   // VPEVLBasedIVPHIRecipe except for the canonical IV increment.
1488   CanonicalIVPHI->replaceAllUsesWith(EVLPhi);
1489   CanonicalIVIncrement->setOperand(0, CanonicalIVPHI);
1490   // TODO: support unroll factor > 1.
1491   Plan.setUF(1);
1492   return true;
1493 }
