1495 void VPlanTransforms::dropPoisonGeneratingRecipes(
1496     VPlan &Plan, function_ref<bool(BasicBlock *)> BlockNeedsPredication) {
1497   // Collect recipes in the backward slice of `Root` that may generate a poison
1498   // value that is used after vectorization.
1499   SmallPtrSet<VPRecipeBase *, 16> Visited;
1500   auto CollectPoisonGeneratingInstrsInBackwardSlice([&](VPRecipeBase *Root) {
1501     SmallVector<VPRecipeBase *, 16> Worklist;
1502     Worklist.push_back(Root);
1503 
1504     // Traverse the backward slice of Root through its use-def chain.
1505     while (!Worklist.empty()) {
1506       VPRecipeBase *CurRec = Worklist.pop_back_val();
1507 
1508       if (!Visited.insert(CurRec).second)
1509         continue;
1510 
1511       // Prune search if we find another recipe generating a widen memory
1512       // instruction. Widen memory instructions involved in address computation
1513       // will lead to gather/scatter instructions, which don't need to be
1514       // handled.
1515       if (isa<VPWidenMemoryRecipe>(CurRec) || isa<VPInterleaveRecipe>(CurRec) ||
1516           isa<VPScalarIVStepsRecipe>(CurRec) || isa<VPHeaderPHIRecipe>(CurRec))
1517         continue;
1518 
1519       // This recipe contributes to the address computation of a widen
1520       // load/store. If the underlying instruction has poison-generating flags,
1521       // drop them directly.
1522       if (auto *RecWithFlags = dyn_cast<VPRecipeWithIRFlags>(CurRec)) {
1523         VPValue *A, *B;
1524         using namespace llvm::VPlanPatternMatch;
1525         // Dropping disjoint from an OR may yield incorrect results, as some
1526         // analysis may have converted it to an Add implicitly (e.g. SCEV used
1527         // for dependence analysis). Instead, replace it with an equivalent Add.
1528         // This is possible as all users of the disjoint OR only access lanes
1529         // where the operands are disjoint or poison otherwise.
1530         if (match(RecWithFlags, m_BinaryOr(m_VPValue(A), m_VPValue(B))) &&
1531             RecWithFlags->isDisjoint()) {
1532           VPBuilder Builder(RecWithFlags);
1533           VPInstruction *New = Builder.createOverflowingOp(
1534               Instruction::Add, {A, B}, {false, false},
1535               RecWithFlags->getDebugLoc());
1536           New->setUnderlyingValue(RecWithFlags->getUnderlyingValue());
1537           RecWithFlags->replaceAllUsesWith(New);
1538           RecWithFlags->eraseFromParent();
1539           CurRec = New;
1540         } else
1541           RecWithFlags->dropPoisonGeneratingFlags();
1542       } else {
1543         Instruction *Instr = dyn_cast_or_null<Instruction>(
1544             CurRec->getVPSingleValue()->getUnderlyingValue());
1545         (void)Instr;
1546         assert((!Instr || !Instr->hasPoisonGeneratingFlags()) &&
1547                "found instruction with poison generating flags not covered by "
1548                "VPRecipeWithIRFlags");
1549       }
1550 
1551       // Add new definitions to the worklist.
1552       for (VPValue *Operand : CurRec->operands())
1553         if (VPRecipeBase *OpDef = Operand->getDefiningRecipe())
1554           Worklist.push_back(OpDef);
1555     }
1556   });
1557 
1558   // Traverse all the recipes in the VPlan and collect the poison-generating
1559   // recipes in the backward slice starting at the address of a VPWidenRecipe or
1560   // VPInterleaveRecipe.
1561   auto Iter = vp_depth_first_deep(Plan.getEntry());
1562   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(Iter)) {
1563     for (VPRecipeBase &Recipe : *VPBB) {
1564       if (auto *WidenRec = dyn_cast<VPWidenMemoryRecipe>(&Recipe)) {
1565         Instruction &UnderlyingInstr = WidenRec->getIngredient();
1566         VPRecipeBase *AddrDef = WidenRec->getAddr()->getDefiningRecipe();
1567         if (AddrDef && WidenRec->isConsecutive() &&
1568             BlockNeedsPredication(UnderlyingInstr.getParent()))
1569           CollectPoisonGeneratingInstrsInBackwardSlice(AddrDef);
1570       } else if (auto *InterleaveRec = dyn_cast<VPInterleaveRecipe>(&Recipe)) {
1571         VPRecipeBase *AddrDef = InterleaveRec->getAddr()->getDefiningRecipe();
1572         if (AddrDef) {
1573           // Check if any member of the interleave group needs predication.
1574           const InterleaveGroup<Instruction> *InterGroup =
1575               InterleaveRec->getInterleaveGroup();
1576           bool NeedPredication = false;
1577           for (int I = 0, NumMembers = InterGroup->getNumMembers();
1578                I < NumMembers; ++I) {
1579             Instruction *Member = InterGroup->getMember(I);
1580             if (Member)
1581               NeedPredication |= BlockNeedsPredication(Member->getParent());
1582           }
1583 
1584           if (NeedPredication)
1585             CollectPoisonGeneratingInstrsInBackwardSlice(AddrDef);
1586         }
1587       }
1588     }
1589   }
1590 }
